Here's a complete example:

**XAML**
```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding SelectedItem}"
                    SelectionChangedCommand="{Binding SelectionChangedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="*,Auto">
                    <Label Text="{Binding Name}" FontSize="16" />
                    <Label Grid.Column="1" Text="{Binding Status}"
                           TextColor="Gray" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
    </CollectionView>
</RefreshView>
```

**ViewModel** (using CommunityToolkit.Mvvm)
```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private bool _isRefreshing;

    [ObservableProperty]
    private Item? _selectedItem;

    public ObservableCollection<Item> Items { get; } = new();

    [RelayCommand]
    private async Task RefreshAsync()
    {
        var data = await _api.GetItemsAsync();
        Items.Clear();
        foreach (var item in data)
            Items.Add(item);
        IsRefreshing = false;           // stops the spinner
    }

    [RelayCommand]
    private async Task SelectionChangedAsync()
    {
        if (SelectedItem is null) return;
        await _nav.GoToAsync("DetailPage", new Dictionary<string, object>
        {
            ["Item"] = SelectedItem
        });
        SelectedItem = null;            // reset so the same row can be tapped again
    }
}
```

**Key binding points:**

| XAML Property | ViewModel Property | Purpose |
|---|---|---|
| `IsRefreshing` | `bool IsRefreshing` | Two-way; set `false` when load finishes to dismiss spinner |
| `Command` (RefreshView) | `RefreshCommand` | Fires on pull-to-refresh |
| `ItemsSource` | `ObservableCollection<Item>` | Data source |
| `SelectedItem` | `Item? SelectedItem` | Two-way; holds current selection |
| `SelectionChangedCommand` | `SelectionChangedCommand` | Fires when selection changes; navigate + null-out to allow re-tap |

**Tips:**
- Set `SelectionMode="Single"` — `None` disables the binding entirely.
- Always reset `SelectedItem = null` after navigating, otherwise tapping the same row a second time won't fire the command.
- `IsRefreshing = false` must be set explicitly; the `RefreshView` won't dismiss itself.
